customProcessors.time:
(value) => {
  const n = Number(value);
  const ms =
    typeof value === "number"
      ? n < 1e12
        ? n * 1000
        : n
      : Date.parse(String(value));
  const d = new Date(ms);
  if (Number.isNaN(d.getTime())) return String(value ?? "");
  const p = (x) => String(x).padStart(2, "0");
  return p(d.getHours()) + ":" + p(d.getMinutes()) + ":" + p(d.getSeconds());
}

customProcessors.datetime:
(value) => {
  const n = Number(value);
  const ms =
    typeof value === "number"
      ? n < 1e12
        ? n * 1000
        : n
      : Date.parse(String(value));
  const d = new Date(ms);
  return Number.isNaN(d.getTime()) ? String(value ?? "") : d.toLocaleString();
}

customProcessors.date:
(value) => {
  const n = Number(value);
  const ms =
    typeof value === "number"
      ? n < 1e12
        ? n * 1000
        : n
      : Date.parse(String(value));
  const d = new Date(ms);
  if (Number.isNaN(d.getTime())) return String(value ?? "");
  const p = (x) => String(x).padStart(2, "0");
  return d.getFullYear() + "-" + p(d.getMonth() + 1) + "-" + p(d.getDate());
}

customProcessors.JSONParser:
(value) => {
  if (typeof value !== "string") return value;
  const s = value.trim();
  if (!s) return value;
  try {
    return JSON.parse(s);
  } catch {
    return value;
  }
}
